"""LoanCollection ADT - Manages a collection of loan records."""from typing import List, Optionalfrom datetime import datetimefrom ..models.loan import LoanRecordclass LoanCollection:    """    Abstract Data Type for managing a collection of loans.    Provides efficient lookup by member and book.    """    def __init__(self):        self._loans = {}  # loan_id -> LoanRecord        self._active_loans_by_book = {}  # isbn -> loan_id (only active)        self._loans_by_member = {}  # member_id -> list of loan_ids    def add_loan(self, loan):        """        Add a new loan to the collection.        Raises:            ValueError: If book already has an active loan.        """        if loan.book_isbn in self._active_loans_by_book:            raise ValueError(f"Book '{loan.book_isbn}' already has an active loan")        self._loans[loan.loan_id] = loan        self._active_loans_by_book[loan.book_isbn] = loan.loan_id        if loan.member_id not in self._loans_by_member:            self._loans_by_member[loan.member_id] = []        self._loans_by_member[loan.member_id].append(loan.loan_id)    def get_active_loan_for_book(self, isbn):        """Return the active loan for a book, or None."""        loan_id = self._active_loans_by_book.get(isbn)        if loan_id:            return self._loans.get(loan_id)        return None    def get_loans_for_member(self, member_id):        """Return all loans (active and returned) for a member."""        loan_ids = self._loans_by_member.get(member_id, [])        return [self._loans[lid] for lid in loan_ids if lid in self._loans]    def get_active_loans_for_member(self, member_id):        """Return only active loans for a member."""        return [loan for loan in self.get_loans_for_member(member_id) if loan.is_active()]    def get_overdue_loans(self, current_date=None):        """Return all overdue active loans."""        check_date = current_date or datetime.now()        overdue = []        for loan_id in self._active_loans_by_book.values():            loan = self._loans[loan_id]            if loan.is_overdue(check_date):                overdue.append(loan)        return overdue    def get_all_active_loans(self):        """Return all currently active loans."""        return [self._loans[lid] for lid in self._active_loans_by_book.values()]    def close_loan(self, isbn):        """        Mark the active loan for a book as closed (returned).        Args:            isbn (str): ISBN of the book being returned        Returns:            LoanRecord or None: The closed loan, or None if no active loan exists.        """        if isbn not in self._active_loans_by_book:            return None        loan_id = self._active_loans_by_book[isbn]        loan = self._loans.get(loan_id)        if loan:            # Remove from active tracking            del self._active_loans_by_book[isbn]            # Note: The loan record itself remains in self._loans for history        return loan    def count_active(self):        """Return number of active loans."""        return len(self._active_loans_by_book)    def count_total(self):        """Return total number of loans (including returned)."""        return len(self._loans)